                  'claude-sonnet-4-6',
                  'claude-opus-4-8',
                  'gemini-3.1-pro-preview'
              )
              OR json_extract(config_json, '$.model') LIKE 'gpt-%'
              OR json_extract(config_json, '$.model') LIKE 'gemini-%'
              OR json_extract(config_json, '$.model') LIKE 'glm-%'
          )
      )
  );
